const body = $input.first().json.body ?? $input.first().json;

const data = body.data ?? body.dados;
if (!data) return [];

if (data.key?.fromMe === true) return [];

const remoteJid = data.key?.remoteJid;
if (!remoteJid) return [];
if (remoteJid.endsWith('@g.us')) return [];

const telefone = remoteJid.replace('@s.whatsapp.net', '');

let texto = '';
let tipoMensagem = data.messageType ?? 'unknown';

if (data.message?.conversation) {
  texto = data.message.conversation;
} else if (data.message?.extendedTextMessage?.text) {
  texto = data.message.extendedTextMessage.text;
} else if (data.message?.imageMessage?.caption) {
  texto = data.message.imageMessage.caption;
  tipoMensagem = 'imagem';
} else if (data.message?.audioMessage) {
  tipoMensagem = 'audio';
  texto = '[áudio]';
} else {
  return [];
}

if (!texto.trim()) return [];

const instance = body.instance ?? body.instância ?? body.instancia ?? 'clinica01';

return [{
  json: {
    telefone,
    nome: data.pushName ?? 'Cliente',
    texto: texto.trim(),
    tipoMensagem,
    messageId: data.key?.id ?? '',
    timestamp: data.messageTimestamp ?? Math.floor(Date.now() / 1000),
    instancia: instance,
    remoteJid
  }
}];

const input = $input.first().json;

// Tenta ambos os nomes (n8n pode traduzir)
let ctx;
for (const n of ['Haicai de Montar Prompt', 'Montar Prompt Haiku']) {
  try { ctx = $(n).first().json; break; } catch(e) {}
}
if (!ctx) ctx = { telefone:'', nome:'Cliente', texto:'', tipoMensagem:'text', remoteJid:'', instancia:'clinica', timestamp: Math.floor(Date.now()/1000), messageId:'' };

if (input.error || !input.content) {
  return [{ json: { ...ctx, intent:'OUTRO', confidence:0, resposta:`Oi, ${ctx.nome}! Estou com instabilidade. Pode repetir em instantes? 😊`, haiku_raw: JSON.stringify(input.error ?? 'sem resposta') } }];
}

const rawText = input.content?.[0]?.text ?? '{}';
let parsed;
try {
  parsed = JSON.parse(rawText.replace(/```json?/g,'').replace(/```/g,'').trim());
} catch(e) {
  parsed = { intent:'OUTRO', confidence:0.5, resposta:'Olá! Como posso te ajudar hoje? 😊' };
}

const validos = ['AGENDAR','DUVIDA_PROCEDIMENTO','DUVIDA_PRECO','POS_PROCEDIMENTO','LEAD_NOVO','RECLAMACAO','OUTRO'];
if (!validos.includes(parsed.intent)) parsed.intent = 'OUTRO';

return [{ json: { ...ctx, intent: parsed.intent, confidence: parsed.confidence ?? 0.8, resposta: parsed.resposta ?? 'Como posso te ajudar?', haiku_raw: rawText } }];

const { telefone, nome, texto, intent, resposta, remoteJid, instancia, timestamp, messageId, confidence } = $input.first().json;

const mensagemParaCliente = resposta || `${nome}, sinto muito pelo inconveniente. Nossa equipe já foi notificada e entrará em contato em breve.`;

const mensagemParaEquipe =
  '🚨 *ESCALAÇÃO — ATENDIMENTO MANUAL NECESSÁRIO*\n\n' +
  `👤 Cliente: ${nome}\n` +
  `📱 Telefone: ${telefone}\n` +
  `💬 Mensagem: "${texto}"\n` +
  `🏷️ Intent: ${intent}\n\n` +
  'Por favor, assuma o atendimento manualmente.';

return [{
  json: {
    telefone,
    nome,
    texto,
    intent,
    confidence,
    remoteJid,
    instancia,
    timestamp,
    messageId,
    mensagemParaCliente,
    mensagemParaEquipe,
    ehEscalacao: true
  }
}];

const ctx = $('Normalizar Payload').first().json;
let rota = 'CLASSIFICAR';
try {
  for (const item of $input.all()) {
    const s = item.json || {};
    if (String(s.Telefone || '') === String(ctx.telefone) && String(s.Status || '').toLowerCase() === 'ativo') {
      const ag = String(s.Agente || '').toUpperCase();
      if (ag.includes('BIA')) rota = 'BIA';
      else if (ag.includes('CLARA')) rota = 'CLARA';
    }
  }
} catch (e) {}
return [{ json: { ...ctx, rota, intent: 'CONTINUACAO' } }];
